function validerNote(valeur) { let note = parseFloat(valeur); return !isNaN(note) && note >= 0 && note <= 20; }

document.querySelectorAll('.champ-note').forEach(champ => {
  champ.addEventListener('blur', function() {
    if (!validerNote(this.value)) {
      alert('Note invalide : doit être entre 0 et 20');
      this.focus();
    }
  });
});
